# Validate incoming WebSocket messages defensively
import json
from pydantic import BaseModel, validator, ValidationError

class IncomingMessage(BaseModel):
    type: str
    content: str

    @validator("type")
    def type_must_be_known(cls, v):
        allowed = {"prompt", "stop", "ping"}
        if v not in allowed:
            raise ValueError(f"Unknown message type: {v!r}")
        return v

    @validator("content")
    def content_length_limit(cls, v):
        if len(v) > 10_000:
            raise ValueError("Content too long (max 10,000 chars)")
        return v

async def handler(websocket):
    async for raw in websocket:
        try:
            data = json.loads(raw)
            msg = IncomingMessage(**data)  # Raises ValidationError if invalid
            # Process validated message
        except (json.JSONDecodeError, ValidationError) as e:
            await websocket.close(code=1003, reason=f"Invalid message: {e}")
            return
